var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SORI_EXTRA_NULL_NULL","text":{"KOREA":"언니, 이쪽이야. 빨리 와.","JPN":"お姉ちゃん、こっちだよ。早く来て。","ENG":"Sobin, this way. Hurry.","TWN":"姐姐，這邊，快來。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"SORI_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOBIN_KID_NULL_NULL","text":{"KOREA":"소리야, 진짜 여기 재밌는 게 있어?","JPN":"コナツちゃん、面白いことって何？本当にこんなところで見たの？","ENG":"Sori, are you sure there's something fun here?","TWN":"昭璃，這裡真的有好玩的嗎？"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"SORI_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOBIN_KID_NULL_NULL","text":{"KOREA":"아까부터 사람이 안 보이는데...... 어른들도 없고......","JPN":"さっきから誰も見かけないし……大人たちもいないけど……","ENG":"I haven't seen anybody for a while... And there are no adults here...","TWN":"從剛才開始就一個人都看不到……也沒有大人……"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"SORI_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SORI_EXTRA_NULL_NULL","text":{"KOREA":"왜 그래, 언니. 오늘은 나랑 놀아 주기로 했잖아.","JPN":"どうしたのよ、お姉ちゃん。今日はアタシと遊ぶ約束だったじゃない。","ENG":"What's wrong, Sobin? You promised to play with me today.","TWN":"怎麼了，姐姐。妳不是說好，今天要陪我玩的嗎？"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"SORI_EXTRA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SORI_EXTRA_NULL_NULL","text":{"KOREA":"혹시 겁나서 그래?","JPN":"もしかして怖くなっちゃった？","ENG":"Are you scared?","TWN":"該不會是害怕了吧？"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"SORI_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOBIN_KID_NULL_NULL","text":{"KOREA":"나, 난 겁 안 나! 언니인걸!","JPN":"こ、怖くなんかないもん！お姉ちゃんだもん！","ENG":"I-I'm not scared! I'm your older sister!","TWN":"我、我才不怕！我可是姐姐！"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"SORI_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MAN_EXTRA_NULL_NULL","text":{"KOREA":"오, 약속한 시간에 딱 맞춰 왔구나.","JPN":"おお、約束の時間ぴったりに来てくれたね。","ENG":"Oh, you're right on time.","TWN":"哦，妳來得很準時呢。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"MAN_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SORI_EXTRA_NULL_NULL","text":{"KOREA":"아저씨!","JPN":"おじさん！","ENG":"Mister!","TWN":"叔叔！"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"SORI_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOBIN_KID_NULL_NULL","text":{"KOREA":"소리야! 가면 안 돼!","JPN":"コナツちゃん！行っちゃダメ！","ENG":"Sori! Don't go!","TWN":"昭璃！不要過去！"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOBIN_KID_NULL_NULL","text":{"KOREA":"선생님이 모르는 사람 따라가면 안 된다고 했잖아!","JPN":"知らない人について行っちゃダメだって、先生が言ってたじゃない！","ENG":"The teacher said not to follow strangers!","TWN":"老師不是說不能跟陌生人走嗎！"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SORI_EXTRA_NULL_NULL","text":{"KOREA":"괜찮아, 착한 아저씨거든! 언니가 이제부터 그 못난이들이랑 안 놀게 해 준댔어!","JPN":"平気よ、おじさんは優しいもん！もうお姉ちゃんがあのぶさいくたちと遊ばないようにしてくれるって言ってたの！","ENG":"It's okay, he's really nice! He's going to help you get rid of those losers!","TWN":"不要緊，這個叔叔是好人！他說可以讓姐姐再也不用跟那些笨蛋們一起玩！"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"SORI_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOBIN_KID_NULL_NULL","text":{"KOREA":"걔네들은 못난이가 아니라 내 친구야!","JPN":"ぶさいくじゃないよ。私の友達だもん！","ENG":"They're not losers, they're my friends!","TWN":"他們不是笨蛋！他們是我的朋友！"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOBIN_KID_NULL_NULL","text":{"KOREA":"아, 아저씨가 소빈이한테 이상한 얘기 한 거죠? 경찰 부를 거야!","JPN":"お、おじさんがコナツちゃんに変なことを言ったんですね？ケーサツを呼びますよ！","ENG":"D-did you say something weird to Sori? I'm calling the cops!","TWN":"叔、叔叔對昭璃說了奇怪的話吧？我要叫警察了！"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MAN_EXTRA_NULL_NULL","text":{"KOREA":"하하. 이상한 얘기라니. 아저씨는 그냥 좀 도와 준다고 했단다.","JPN":"ハハッ、変なこととは心外だな。おじさんは親切心で力を貸すと言ったんだ。","ENG":"Hah hah. What do you mean, something weird? I just told her that I'm going to help her.","TWN":"哈哈！居然說是奇怪的話。叔叔只是幫她一個小忙而已。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":null,"R":{"char_id":"MAN_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MAN_EXTRA_NULL_NULL","text":{"KOREA":"그래. 그런 애들이랑 놀고 있으면 안 되지.","JPN":"お嬢ちゃんの言うとおりさ。あんな子たちと遊んでちゃいけないんだぞ。","ENG":"Yes. You really shouldn't be playing with those kids.","TWN":"是啊，妳不能跟那樣的小孩玩。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":null,"R":{"char_id":"MAN_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SOBIN_KID_NULL_NULL","text":{"KOREA":"......!","JPN":"……！","ENG":"......!","TWN":"……！"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SORI_EXTRA_NULL_NULL","text":{"KOREA":"아, 아저씨? 이 사람들은 누구야? 아저씨 부하들?","JPN":"お、おじさん？この人たちは誰？おじさんの会社の人たちなの？","ENG":"M-Mister? Who are these people? Are they your employees?","TWN":"叔、叔叔？這些人是誰啊？叔叔的手下嗎？"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"MAN_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORI_EXTRA_NULL_NULL","face":"UNIT_HATE"}}}}]`);export{e as default};